import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { truncateContent } from './truncateContent';

describe('truncateContent', () => {
  it('should handle happy path when content is longer than maxLength', () => {
    const longText = 'a'.repeat(100);
    const result = truncateContent(longText, 80);
    expect(result).toBe('a'.repeat(80) + '...');
  });

  it('should handle edge case when content length equals maxLength', () => {
    const exactText = 'b'.repeat(80);
    const result = truncateContent(exactText, 80);
    // No truncation should occur, no ellipsis added
    expect(result).toBe(exactText);
  });

  it('should handle null/empty inputs gracefully', () => {
    // null input
    // @ts-ignore – testing runtime behaviour with null
    expect(truncateContent(null, 50)).toBe('');
    // undefined input
    // @ts-ignore
    expect(truncateContent(undefined, 50)).toBe('');
    // empty string
    expect(truncateContent('', 50)).toBe('');
    // zero maxLength should return empty string even if content exists
    expect(truncateContent('some content', 0)).toBe('');
  });
});

